S)    SELECT   ' MHEInboundSchedulerTrigger ' , ' COM_WM' , 'SHIPPING' , 'Peer Failover Information for MHE Inbound' , 'Peer Failover Information for MHE Inbound' ,           0, 0, 4, 'TEXTBOX' ,  NULL , 0, NULL , 0, NULL , 1, NULL , 0, 'null' , NULL ,  NULL , NULL      FROM   dual     WHERE   NOT

EXISTS ( SELECT   1              FROM   param_def             WHERE   PARAM_DEF_ID =  ' MHEInboundSchedulerTrigger '               AND   PARAM_GROUP_ID =  'COM_WM'               AND   PARAM_SUBGROUP_ID =  'SHIPPING' ); INSERT   INTO   PARAM_DEF    (PARAM_DEF_ID, PARAM_GROUP_ ID,PARAM _SUBGROUP_ID,PARAM_NAME,DESCRIPTION,IS_DISABLED,IS_REQUIRED,DATA_TYPE,UI_TYPE,MIN_VALUE,IS_MIN_INC,MAX_VALUE,IS_MAX_INC,     DFLT_ VALUE,DISPLAY _ORDER,VALUE_GENERATOR_CLASS,IS_LOCALIZABLE, PARAM_CATEGORY,CARR_DFLT_VALUE,BP_DFLT_VALUE, PARAM_VALIDATOR_CLASS)    SELECT   ' MHEOutboundSchedulerTrigger ' , ' COM_WM' , 'SHIPPING' , 'Peer Failover Information for MHE Outbound' , 'Peer Failover Information for MHE Outbound' ,           0, 0,4, 'TEXTBOX ' , NULL , 0, NULL ,0,  NULL ,1, NULL ,0, 'null' , NULL , NULL , NULL      FROM   dual     WHERE   NOT   EXISTS ( SELECT   1              FROM   param_def             WHERE   PARAM_DEF_ID =  ' MHEOutboundSchedulerTrigger '               AND   PARAM_GROUP_ID =  'COM_WM'               AND   PARAM_SUBGROUP_ID =  'SHIPPING' );   COMMIT ;
